//! Spec-compliance tests: Content Types (ISO 29500-1 §17.3.3, §17.5.2, §22)
//!
//! These tests verify our implementation correctly handles various OOXML
//! content types (images, SDT, math, ruby, AlternateContent).
//! Tests marked `#[ignore]` document known gaps.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use std::fs;

use stemma::{BlockNode, CanonDoc, DocxRuntime, ExportMode, InlineNode, OpaqueKind};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/content";

// ── helpers ──────────────────────────────────────────────────────────────
/// Collect all OpaqueInline nodes from all paragraphs in a document.
fn all_opaque_inlines(doc: &CanonDoc) -> Vec<&stemma::OpaqueInlineNode> {
    let mut result = Vec::new();
    for tracked_block in &doc.blocks {
        collect_opaques_from_block(&tracked_block.block, &mut result);
    }
    result
}

fn collect_opaques_from_block<'a>(
    block: &'a BlockNode,
    out: &mut Vec<&'a stemma::OpaqueInlineNode>,
) {
    match block {
        BlockNode::Paragraph(p) => {
            for inline in p.all_inlines() {
                if let InlineNode::OpaqueInline(o) = inline {
                    out.push(o);
                }
            }
        }
        BlockNode::Table(t) => {
            for row in &t.rows {
                for cell in &row.cells {
                    for b in &cell.blocks {
                        collect_opaques_from_block(b, out);
                    }
                }
            }
        }
        BlockNode::OpaqueBlock(_) => {}
    }
}

/// Check if any paragraph contains an OpaqueInline of the given kind.
fn has_opaque_kind(doc: &CanonDoc, kind_match: fn(&OpaqueKind) -> bool) -> bool {
    all_opaque_inlines(doc).iter().any(|o| kind_match(&o.kind))
}

/// Check if any block-level opaque has the given kind.
fn has_opaque_block_kind(doc: &CanonDoc, kind_match: fn(&OpaqueKind) -> bool) -> bool {
    doc.blocks.iter().any(|tb| {
        if let BlockNode::OpaqueBlock(o) = &tb.block {
            kind_match(&o.kind)
        } else {
            false
        }
    })
}

// ── Inline image ─────────────────────────────────────────────────────────

/// ISO 29500-1 §20.4.2.8: Inline image (wp:inline inside w:drawing).
///
/// A paragraph with an embedded inline image should produce an OpaqueInline
/// with kind Drawing.
#[test]
fn spec_inline_image_produces_drawing_opaque() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "inline-image");

    assert!(
        has_opaque_kind(&doc, |k| matches!(k, OpaqueKind::Drawing)),
        "document should contain at least one OpaqueInline with kind Drawing"
    );
}

/// Inline image should have raw_xml for roundtripping.
#[test]
fn spec_inline_image_has_raw_xml() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "inline-image");

    let drawings: Vec<_> = all_opaque_inlines(&doc)
        .into_iter()
        .filter(|o| matches!(o.kind, OpaqueKind::Drawing))
        .collect();

    assert!(!drawings.is_empty(), "should have at least one Drawing");
    assert!(
        drawings[0].raw_xml.is_some(),
        "Drawing OpaqueInline should have raw_xml for roundtripping"
    );
}

/// Inline image should have a content_hash for cross-document comparison.
#[test]
fn spec_inline_image_has_content_hash() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "inline-image");

    let drawings: Vec<_> = all_opaque_inlines(&doc)
        .into_iter()
        .filter(|o| matches!(o.kind, OpaqueKind::Drawing))
        .collect();

    assert!(!drawings.is_empty(), "should have at least one Drawing");
    assert!(
        drawings[0].content_hash.is_some(),
        "Drawing OpaqueInline should have content_hash"
    );
}

