// ── Block-level SDT ──────────────────────────────────────────────────────

/// ISO 29500-1 §17.5.2.32: Block-level SDT wrapping a paragraph.
///
/// Body-level SDTs are preserved as OpaqueBlocks with kind Sdt.
/// This ensures the content control wrapper (sdtPr) is roundtripped.
#[test]
fn spec_block_sdt_content_is_accessible() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "block-sdt");

    // The document should have the SDT as an opaque block or inline opaque, or the text should be accessible
    let all_text = extract_all_text(&doc);
    assert!(
        all_text.contains("Content inside block SDT")
            || has_opaque_kind(&doc, |k| matches!(k, OpaqueKind::Sdt))
            || has_opaque_block_kind(&doc, |k| matches!(k, OpaqueKind::Sdt)),
        "block SDT content should be accessible as text, Sdt inline opaque, or Sdt opaque block. All text: {all_text}"
    );
}

fn extract_all_text(doc: &CanonDoc) -> String {
    let mut text = String::new();
    for tracked_block in &doc.blocks {
        extract_text_from_block(&tracked_block.block, &mut text);
    }
    text
}

fn extract_text_from_block(block: &BlockNode, out: &mut String) {
    match block {
        BlockNode::Paragraph(p) => {
            for inline in p.all_inlines() {
                if let InlineNode::Text(t) = inline {
                    out.push_str(&t.text);
                }
            }
            out.push('\n');
        }
        BlockNode::Table(t) => {
            for row in &t.rows {
                for cell in &row.cells {
                    for b in &cell.blocks {
                        extract_text_from_block(b, out);
                    }
                }
            }
        }
        BlockNode::OpaqueBlock(_) => {}
    }
}

