/// ISO 29500-1 §22: Inline math equation (m:oMath).
///
/// Should produce an OpaqueInline with kind OmmlInline.
#[test]
fn spec_inline_math_produces_omml_opaque() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "inline-math");

    assert!(
        has_opaque_kind(&doc, |k| matches!(k, OpaqueKind::OmmlInline)),
        "document should contain an OpaqueInline with kind OmmlInline"
    );
}

/// Inline math should have raw_xml for the equation content.
#[test]
fn spec_inline_math_has_raw_xml() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "inline-math");

    let math_nodes: Vec<_> = all_opaque_inlines(&doc)
        .into_iter()
        .filter(|o| matches!(o.kind, OpaqueKind::OmmlInline))
        .collect();

    assert!(
        !math_nodes.is_empty(),
        "should have at least one OmmlInline node"
    );
    assert!(
        math_nodes[0].raw_xml.is_some(),
        "Omml OpaqueInline should have raw_xml"
    );
}

