/// ECMA-376 Part 3 (MCE): mc:AlternateContent with Choice/Fallback.
///
/// The MC block should be handled — the Choice branch (w:drawing) should
/// be selected, producing an OpaqueInline with kind Drawing.
#[test]
fn spec_alternate_content_is_handled() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "alternate-content");

    // MC block should produce a Drawing opaque (from the Choice branch with w:drawing)
    assert!(
        has_opaque_kind(&doc, |k| matches!(k, OpaqueKind::Drawing)),
        "mc:AlternateContent should be handled as OpaqueInline with Drawing kind"
    );
}

// ── Image roundtrip ──────────────────────────────────────────────────────

/// Image roundtrip: import a doc with an image, export, reimport.
/// Verify content_hash is preserved across the roundtrip.
#[test]
fn spec_image_roundtrip_preserves_content_hash() {
    let (runtime, doc1) = common::import_fixture(FIXTURES, "inline-image");

    // Get the content_hash from the first import
    let drawings1: Vec<_> = all_opaque_inlines(&doc1)
        .into_iter()
        .filter(|o| matches!(o.kind, OpaqueKind::Drawing))
        .collect();
    assert!(!drawings1.is_empty(), "first import should have Drawing");
    let hash1 = drawings1[0]
        .content_hash
        .as_ref()
        .expect("should have content_hash");

    // Export and reimport
    let path = format!("{FIXTURES}/inline-image/input.docx");
    let bytes = fs::read(&path).unwrap();
    let import1 = runtime.import_docx(&bytes).expect("import");
    let export_bytes = runtime
        .export_docx(&import1.doc_handle, ExportMode::Redline)
        .expect("export");

    let import2 = runtime.import_docx(&export_bytes).expect("reimport");
    let view2 = runtime.view(&import2.doc_handle).expect("view2");
    let doc2 = view2.canonical;

    let drawings2: Vec<_> = all_opaque_inlines(&doc2)
        .into_iter()
        .filter(|o| matches!(o.kind, OpaqueKind::Drawing))
        .collect();
    assert!(!drawings2.is_empty(), "reimport should have Drawing");
    let hash2 = drawings2[0]
        .content_hash
        .as_ref()
        .expect("reimport should have content_hash");

    assert_eq!(
        hash1, hash2,
        "content_hash should be preserved across import-export-reimport roundtrip"
    );
}
